package net.dinomite.ytpodcast.pluginsimport io.ktor.http.ContentTypeimport io.ktor.http.HttpHeadersimport io.ktor.http.HttpStatusCodeimport io.ktor.http.HttpStatusCode.Companion.BadRequestimport io.ktor.http.HttpStatusCode.Companion.InternalServerErrorimport io.ktor.server.application.Applicationimport io.ktor.server.plugins.originimport io.ktor.server.request.headerimport io.ktor.server.request.hostimport io.ktor.server.request.portimport io.ktor.server.response.headerimport io.ktor.server.response.respondimport io.ktor.server.response.respondBytesimport io.ktor.server.response.respondTextimport io.ktor.server.routing.getimport io.ktor.server.routing.routingimport net.dinomite.ytpodcast.controller.PlaylistControllerimport net.dinomite.ytpodcast.models.ErrorResponseimport org.slf4j.LoggerFactory@Suppress("Detekt:LongMethod", "Detekt:CyclomaticComplexMethod", "Detekt:TooGenericExceptionCaught")fun Application.configureRouting(playlistController: PlaylistController) {    val logger = LoggerFactory.getLogger(Application::class.java)    routing {        get("/") { call.respondText("YouTube to Podcast RSS Feed Converter") }        get("/health") { call.respond(HttpStatusCode.OK, mapOf("status" to "healthy")) }        // Get RSS feed for a playlist        get("/feed/{playlistId}") {            try {                val playlistId = call.parameters["playlistId"]                    ?: call.respond(BadRequest, ErrorResponse("invalid_request", "Missing playlist ID"))                require(playlistId is String)                val baseUrl = "${call.request.origin.scheme}://${call.request.host()}:${call.request.port()}"                val rssFeed = playlistController.playlistFeed(baseUrl, playlistId)                call.respondText(rssFeed, ContentType.Application.Rss)            } catch (e: Exception) {                logger.error("Failed to get RSS feed", e)                call.respond(InternalServerError, ErrorResponse("internal_error", "Failed to get RSS feed"))            }        }        // Get episode audio file        get("/show/{showId}/episodes/{episodeId}.mp3") {            try {                val showId = call.parameters["showId"]                val episodeIdWithExt = call.parameters["episodeId"]                if (showId == null || episodeIdWithExt == null) {                    call.respond(BadRequest, ErrorResponse("invalid_request", "Missing show or episode ID"))                }                requireNotNull(showId)                requireNotNull(episodeIdWithExt)                // Remove .mp3 extension if present                val episodeId = episodeIdWithExt.removeSuffix(".mp3")                val mp3Data = playlistController.audioFile(showId, episodeId)                // Set appropriate headers for audio streaming                call.response.header(HttpHeaders.ContentType, "audio/mpeg")                call.response.header(HttpHeaders.ContentDisposition, "inline; filename=\"$episodeId.mp3\"")                call.response.header(HttpHeaders.AcceptRanges, "bytes")                call.response.header(HttpHeaders.ContentLength, mp3Data.size.toString())                // Support for range requests (for seeking in podcast players)                val range = call.request.header(HttpHeaders.Range)                if (range != null && range.startsWith("bytes=")) {                    val rangeSpec = range.substring(6)                    val rangeParts = rangeSpec.split("-")                    val start = rangeParts[0].toLongOrNull() ?: 0                    val end = if (rangeParts.size > 1 && rangeParts[1].isNotEmpty()) {                        rangeParts[1].toLongOrNull() ?: (mp3Data.size - 1).toLong()                    } else {                        (mp3Data.size - 1).toLong()                    }                    val actualEnd = minOf(end, (mp3Data.size - 1).toLong())                    val contentLength = actualEnd - start + 1                    call.response.status(HttpStatusCode.PartialContent)                    call.response.header(HttpHeaders.ContentRange, "bytes $start-$actualEnd/${mp3Data.size}")                    call.response.header(HttpHeaders.ContentLength, contentLength.toString())                    call.respondBytes(mp3Data.sliceArray(start.toInt()..actualEnd.toInt()))                } else {                    call.respondBytes(mp3Data)                }            } catch (e: Exception) {                logger.error("Failed to get episode audio", e)                call.respond(InternalServerError, ErrorResponse("internal_error", "Failed to get episode audio"))            }        }//        // Get playlist info//        get("/api/playlist/{playlistId}") { playlistController.playlistInfo(call) }////        // Get video info//        get("/api/video/{videoId}") {//            try {//                val videoId = call.parameters["videoId"]//                    ?: return@get call.respond(//                        HttpStatusCode.BadRequest,//                        ErrorResponse("invalid_request", "Missing video ID")//                    )////                logger.info("Getting info for video: $videoId")////                val videoInfo = youTubeService.getVideoInfo(videoId)//                call.respond(videoInfo)//            } catch (e: Exception) {//                logger.error("Failed to get video info", e)//                call.respond(//                    HttpStatusCode.InternalServerError,//                    ErrorResponse("internal_error", "Failed to get video info")//                )//            }//        }    }}